<!DOCTYPE html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title><?= htmlspecialchars($title["name"]) ?></title><link rel="icon" href="static/favicon.svg"><link rel="stylesheet" href="static/common.css"></head><body><div class="title"><img class="banner" src="<?= $title["banner"] ?>"><a class="name" href="#"><?= htmlspecialchars($title["name"]) ?></a><div class="artists"><?php foreach ($artists as $artist): ?><div class="artist"><a class="name"<?php if ($artist["profile"] !== null): ?> href="<?= $artist["profile"] ?>" target="_blank" rel="noopener noreferrer"<?php endif; ?>><?= htmlspecialchars($artist["name"]) ?></a><div class="role"><?= $artist["role"] ?></div></div><?php endforeach; ?></div><div class="synopsis"><?= htmlspecialchars($title["synopsis"]) ?></div><div class="subtitles"><?php foreach ($subtitles as $subtitle): ?><a class="subtitle" href="read.php?titleId=<?= $title_id ?>&subtitleId=<?= $subtitle["id"] ?>" target="_blank"><img class="thumbnail" src="<?= $subtitle["thumbnail"] ?>"><div class="desc"><div class="name"><?= htmlspecialchars($subtitle["name"]) ?></div><div class="date"><?= date("y.m.d", $subtitle["date"] + 32400) ?></div></div></a><?php endforeach; ?></div></div><div class="navigator"><a class="button"<?php if ($page > 1): ?> href="list.php?titleId=<?= $title_id ?>&page=<?= $page - 1 ?>"<?php endif; ?>>&#xf044;</a><?= $page ?> / <?= $page_max ?><a class="button"<?php if ($page < $page_max): ?> href="list.php?titleId=<?= $title_id ?>&page=<?= $page + 1 ?>"<?php endif; ?>>&#xf045;</a></div></div></body></html>